def process_data(data: list, target_ids: set) -> list:
    """O(N) optimized lookup using sets/dicts instead of nested loops."""
    if not data:
        return []
        
    # O(N) iteration, O(1) set lookup
    matched_users = [user for user in data if user.get("id") in target_ids]
    return matched_users

